import { Leaf, LogIn, Shield, Lock, Eye, EyeOff } from "lucide-react";
import { Link, useNavigate } from "react-router";
import { useState } from "react";

export function AdminLogin() {
  const navigate = useNavigate();
  const [credentials, setCredentials] = useState({ email: "", password: "", tfa: "" });
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const DEMO = { email: "admin@demo.com", password: "admin123", tfa: "123456" };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setLoading(true);
    setTimeout(() => {
      if (
        credentials.email.trim() === DEMO.email &&
        credentials.password === DEMO.password &&
        credentials.tfa.trim() === DEMO.tfa
      ) {
        navigate("/admin");
      } else {
        setError("Invalid credentials or 2FA code. Use the demo credentials below.");
        setLoading(false);
      }
    }, 1000);
  };

  const fillDemo = () => {
    setCredentials({ email: DEMO.email, password: DEMO.password, tfa: DEMO.tfa });
    setError("");
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-[#0B5345] via-[#1a7a63] to-[#0B5345] flex items-center justify-center p-8">
      <div className="w-full max-w-md">
        <div className="text-center mb-8">
          <Link to="/" className="inline-flex items-center gap-3 text-white mb-4">
            <Leaf className="w-10 h-10" />
            <div className="text-left">
              <h1 className="text-2xl font-bold">SylhetGo</h1>
              <p className="text-sm text-white/80">Smart Tourism Portal</p>
            </div>
          </Link>
        </div>

        <div className="bg-white rounded-xl shadow-2xl p-8 border-t-4 border-red-500">
          <div className="flex items-center gap-3 mb-6">
            <div className="w-12 h-12 bg-red-500 rounded-lg flex items-center justify-center">
              <Shield className="w-6 h-6 text-white" />
            </div>
            <div>
              <h2 className="text-2xl font-semibold text-gray-800">Master Admin</h2>
              <p className="text-sm text-gray-600">System Control Panel</p>
            </div>
          </div>

          <div className="bg-red-50 border border-red-200 rounded-lg p-4 mb-6">
            <div className="flex items-center gap-2 text-red-800">
              <Lock className="w-4 h-4" />
              <p className="text-sm font-semibold">Restricted Access - Authorized Personnel Only</p>
            </div>
          </div>

          {error && (
            <div className="bg-red-50 border border-red-200 rounded-lg p-3 mb-4 text-sm text-red-700">
              {error}
            </div>
          )}

          <form onSubmit={handleLogin} className="space-y-5">
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Admin Email</label>
              <input
                type="email"
                value={credentials.email}
                onChange={(e) => setCredentials({ ...credentials, email: e.target.value })}
                placeholder="admin@sylhetgo.bd"
                className="w-full px-4 py-3 bg-[#F8F9F9] rounded-lg outline-none focus:ring-2 focus:ring-red-500"
                required
              />
            </div>

            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Admin Password</label>
              <div className="relative">
                <input
                  type={showPassword ? "text" : "password"}
                  value={credentials.password}
                  onChange={(e) => setCredentials({ ...credentials, password: e.target.value })}
                  placeholder="Enter master admin password"
                  className="w-full px-4 py-3 pr-12 bg-[#F8F9F9] rounded-lg outline-none focus:ring-2 focus:ring-red-500"
                  required
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600"
                >
                  {showPassword ? <EyeOff className="w-5 h-5" /> : <Eye className="w-5 h-5" />}
                </button>
              </div>
            </div>

            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Two-Factor Authentication Code</label>
              <input
                type="text"
                value={credentials.tfa}
                onChange={(e) => setCredentials({ ...credentials, tfa: e.target.value.replace(/\D/g, "").slice(0, 6) })}
                placeholder="Enter 6-digit code"
                className="w-full px-4 py-3 bg-[#F8F9F9] rounded-lg outline-none focus:ring-2 focus:ring-red-500 text-center tracking-widest text-xl"
                maxLength={6}
                required
              />
            </div>

            <button
              type="submit"
              disabled={loading}
              className="w-full bg-red-500 text-white py-3 rounded-lg hover:bg-red-600 transition-colors flex items-center justify-center gap-2 disabled:opacity-70"
            >
              {loading ? (
                <span className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin" />
              ) : (
                <LogIn className="w-5 h-5" />
              )}
              {loading ? "Authenticating..." : "Access Admin Dashboard"}
            </button>
          </form>

          <div className="mt-6 pt-6 border-t border-gray-200">
            <button
              onClick={fillDemo}
              className="w-full bg-red-50 border border-red-200 rounded-lg p-3 mb-4 text-left hover:bg-red-100 transition-colors"
            >
              <p className="text-xs text-red-800 font-semibold mb-1">Demo Admin Access (click to fill):</p>
              <p className="text-xs text-red-700">Email: admin@demo.com | Password: admin123 | 2FA: 123456</p>
            </button>
            <div className="space-y-2 text-xs text-gray-600">
              <p className="flex items-center gap-2">
                <Shield className="w-3 h-3 text-red-500" />
                All admin activities are logged and monitored
              </p>
              <p className="flex items-center gap-2">
                <Lock className="w-3 h-3 text-red-500" />
                SSL encrypted connection required
              </p>
            </div>
          </div>
        </div>

        <div className="text-center mt-6">
          <Link to="/" className="text-white hover:text-[#2ECC71] transition-colors text-sm">
            ← Back to Tourist Portal
          </Link>
        </div>
      </div>
    </div>
  );
}

import { ArrowLeft, User, MapPin, Star, DollarSign, Calendar, MessageSquare, ToggleLeft, ToggleRight, CheckCircle, Send, X } from "lucide-react";
import { Link, useNavigate } from "react-router";
import { useState } from "react";

type Booking = {
  id: number;
  name: string;
  destination: string;
  date: string;
  duration: string;
  amount: string;
  status: "pending" | "accepted" | "declined";
};

type Message = {
  from: string;
  preview: string;
  time: string;
  unread?: boolean;
  conversation: string[];
};

export function GuidePanel() {
  const navigate = useNavigate();
  const [isAvailable, setIsAvailable] = useState(true);
  const [profileSaved, setProfileSaved] = useState(false);
  const [profile, setProfile] = useState({
    name: "Rafiq Ahmed",
    specialty: "Tea Estate Expert",
    languages: "Bengali, English, Hindi",
    rate: "500",
    bio: "Passionate about showcasing the beauty of Sreemangal's tea estates. 10+ years of experience guiding international and local tourists.",
    areas: ["Sreemangal", "Lawachara"],
  });
  const [bookings, setBookings] = useState<Booking[]>([
    { id: 1, name: "Sarah Johnson", destination: "Sreemangal Tea Tour", date: "June 15, 2026", duration: "Full Day", amount: "৳4,000", status: "pending" },
    { id: 2, name: "Ahmed Hassan", destination: "Lawachara Trek", date: "June 18, 2026", duration: "Half Day", amount: "৳2,500", status: "pending" },
    { id: 3, name: "Emily Chen", destination: "Tea Estate Photography", date: "June 20, 2026", duration: "6 hours", amount: "৳3,500", status: "pending" },
  ]);
  const [activeMessage, setActiveMessage] = useState<number | null>(null);
  const [msgReply, setMsgReply] = useState("");
  const [messages, setMessages] = useState<Message[]>([
    { from: "Sarah Johnson", preview: "What time should we meet?", time: "10m ago", unread: true, conversation: ["Sarah: What time should we meet?"] },
    { from: "SylhetGo Support", preview: "Profile update approved", time: "2h ago", unread: true, conversation: ["SylhetGo: Profile update approved ✓"] },
    { from: "Ahmed Hassan", preview: "Can we extend the tour?", time: "5h ago", unread: false, conversation: ["Ahmed: Can we extend the tour to include Ratargul?"] },
  ]);

  const allAreas = ["Sreemangal", "Ratargul", "Jaflong", "Bholaganj", "Shamshernagar", "Lawachara"];

  const handleProfileSave = () => {
    setProfileSaved(true);
    setTimeout(() => setProfileSaved(false), 3000);
  };

  const handleBooking = (id: number, action: "accepted" | "declined") => {
    setBookings(prev => prev.map(b => b.id === id ? { ...b, status: action } : b));
  };

  const handleAreaToggle = (area: string) => {
    setProfile(prev => ({
      ...prev,
      areas: prev.areas.includes(area)
        ? prev.areas.filter(a => a !== area)
        : [...prev.areas, area],
    }));
  };

  const handleSendReply = () => {
    if (!msgReply.trim() || activeMessage === null) return;
    setMessages(prev => prev.map((m, idx) =>
      idx === activeMessage
        ? { ...m, conversation: [...m.conversation, `You: ${msgReply.trim()}`], unread: false }
        : m
    ));
    setMsgReply("");
  };

  const unreadCount = messages.filter(m => m.unread).length;

  const handleLogout = () => navigate("/guide");

  return (
    <div className="min-h-screen bg-[#F8F9F9]">
      {/* Message Modal */}
      {activeMessage !== null && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4" onClick={() => setActiveMessage(null)}>
          <div className="bg-white rounded-xl w-full max-w-lg shadow-2xl" onClick={e => e.stopPropagation()}>
            <div className="flex items-center justify-between p-5 border-b">
              <h3 className="font-semibold text-gray-800">{messages[activeMessage].from}</h3>
              <button onClick={() => setActiveMessage(null)}><X className="w-5 h-5 text-gray-400" /></button>
            </div>
            <div className="p-5 space-y-2 max-h-60 overflow-y-auto">
              {messages[activeMessage].conversation.map((line, i) => (
                <p key={i} className={`text-sm p-3 rounded-lg ${line.startsWith("You:") ? "bg-[#2ECC71] text-white ml-8" : "bg-gray-100 text-gray-700 mr-8"}`}>{line}</p>
              ))}
            </div>
            <div className="p-4 border-t flex gap-2">
              <input
                type="text"
                value={msgReply}
                onChange={e => setMsgReply(e.target.value)}
                onKeyDown={e => e.key === "Enter" && handleSendReply()}
                placeholder="Type a reply..."
                className="flex-1 px-4 py-2 bg-gray-100 rounded-lg outline-none focus:ring-2 focus:ring-[#0B5345] text-sm"
              />
              <button onClick={handleSendReply} className="bg-[#2ECC71] text-white px-4 py-2 rounded-lg hover:bg-[#27AE60] transition-colors">
                <Send className="w-4 h-4" />
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Header */}
      <nav className="bg-[#0B5345] text-white px-8 py-4 shadow-lg">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-4">
            <Link to="/" className="hover:text-[#2ECC71] transition-colors">
              <ArrowLeft className="w-5 h-5" />
            </Link>
            <div>
              <h1 className="text-xl font-semibold">Guide Portal</h1>
              <p className="text-xs text-white/80">Manage your profile and bookings</p>
            </div>
          </div>
          <button onClick={handleLogout} className="bg-red-500 px-4 py-2 rounded-lg text-sm hover:bg-red-600 transition-colors">
            Logout
          </button>
        </div>
      </nav>

      <div className="max-w-7xl mx-auto px-8 py-12">
        {/* Welcome Section */}
        <div className="bg-gradient-to-r from-[#0B5345] to-[#2ECC71] text-white rounded-xl p-8 mb-8">
          <div className="flex items-center justify-between">
            <div>
              <h2 className="text-3xl font-semibold mb-2">Welcome back, {profile.name}!</h2>
              <p className="text-white/90">
                You have {bookings.filter(b => b.status === "pending").length} pending tour requests and {bookings.filter(b => b.status === "accepted").length} confirmed bookings this week.
              </p>
            </div>
            <div className="text-right">
              <div className="text-4xl font-bold mb-1">4.9</div>
              <div className="flex items-center justify-end gap-1 mb-1">
                {[1,2,3,4,5].map(i => <Star key={i} className="w-4 h-4 fill-yellow-300 text-yellow-300" />)}
              </div>
              <p className="text-sm text-white/80">340 tours completed</p>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-3 gap-8">
          {/* Left Column */}
          <div className="col-span-2 space-y-6">
            {/* Profile Settings */}
            <div className="bg-white rounded-xl shadow-md p-6">
              <h3 className="text-xl font-semibold text-gray-800 mb-6">Profile Settings</h3>
              <div className="space-y-4">
                <div>
                  <label className="block text-sm text-gray-600 mb-2">Full Name</label>
                  <input
                    type="text"
                    value={profile.name}
                    onChange={e => setProfile(p => ({ ...p, name: e.target.value }))}
                    className="w-full px-4 py-3 bg-[#F8F9F9] rounded-lg outline-none focus:ring-2 focus:ring-[#0B5345]"
                  />
                </div>
                <div>
                  <label className="block text-sm text-gray-600 mb-2">Specialty</label>
                  <select
                    value={profile.specialty}
                    onChange={e => setProfile(p => ({ ...p, specialty: e.target.value }))}
                    className="w-full px-4 py-3 bg-[#F8F9F9] rounded-lg outline-none focus:ring-2 focus:ring-[#0B5345]"
                  >
                    <option>Tea Estate Expert</option>
                    <option>Cultural Heritage</option>
                    <option>Adventure & Trekking</option>
                    <option>Haor Navigation</option>
                    <option>Photography Tours</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm text-gray-600 mb-2">Operating Areas</label>
                  <div className="grid grid-cols-2 gap-3">
                    {allAreas.map(area => (
                      <label key={area} className="flex items-center gap-2 cursor-pointer">
                        <input
                          type="checkbox"
                          checked={profile.areas.includes(area)}
                          onChange={() => handleAreaToggle(area)}
                          className="w-4 h-4 text-[#0B5345] rounded"
                        />
                        <span className="text-sm">{area}</span>
                      </label>
                    ))}
                  </div>
                </div>
                <div>
                  <label className="block text-sm text-gray-600 mb-2">Languages</label>
                  <input
                    type="text"
                    value={profile.languages}
                    onChange={e => setProfile(p => ({ ...p, languages: e.target.value }))}
                    className="w-full px-4 py-3 bg-[#F8F9F9] rounded-lg outline-none focus:ring-2 focus:ring-[#0B5345]"
                  />
                </div>
                <div>
                  <label className="block text-sm text-gray-600 mb-2">Hourly Rate (৳)</label>
                  <input
                    type="number"
                    value={profile.rate}
                    onChange={e => setProfile(p => ({ ...p, rate: e.target.value }))}
                    className="w-full px-4 py-3 bg-[#F8F9F9] rounded-lg outline-none focus:ring-2 focus:ring-[#0B5345]"
                  />
                </div>
                <div>
                  <label className="block text-sm text-gray-600 mb-2">Bio</label>
                  <textarea
                    rows={4}
                    value={profile.bio}
                    onChange={e => setProfile(p => ({ ...p, bio: e.target.value }))}
                    className="w-full px-4 py-3 bg-[#F8F9F9] rounded-lg outline-none focus:ring-2 focus:ring-[#0B5345]"
                  />
                </div>
                <button
                  onClick={handleProfileSave}
                  className="w-full bg-[#2ECC71] text-white py-3 rounded-lg hover:bg-[#27AE60] transition-colors flex items-center justify-center gap-2"
                >
                  {profileSaved ? <><CheckCircle className="w-5 h-5" /> Profile Updated!</> : "Update Profile"}
                </button>
              </div>
            </div>

            {/* Booking Requests */}
            <div className="bg-white rounded-xl shadow-md p-6">
              <h3 className="text-xl font-semibold text-gray-800 mb-6">Pending Booking Requests</h3>
              <div className="space-y-4">
                {bookings.map((booking) => (
                  <div
                    key={booking.id}
                    className={`border rounded-lg p-4 transition-colors ${
                      booking.status === "accepted" ? "border-green-300 bg-green-50" :
                      booking.status === "declined" ? "border-gray-200 bg-gray-50 opacity-60" :
                      "border-gray-200 hover:border-[#0B5345]"
                    }`}
                  >
                    <div className="flex items-start justify-between mb-3">
                      <div>
                        <h4 className="font-semibold text-gray-800">{booking.name}</h4>
                        <p className="text-sm text-gray-600">{booking.destination}</p>
                      </div>
                      <div className="text-right">
                        <div className="font-semibold text-[#0B5345]">{booking.amount}</div>
                        <div className="text-xs text-gray-500">{booking.duration}</div>
                      </div>
                    </div>
                    <div className="flex items-center gap-2 text-sm text-gray-600 mb-3">
                      <Calendar className="w-4 h-4" />
                      <span>{booking.date}</span>
                    </div>
                    {booking.status === "pending" ? (
                      <div className="flex gap-2">
                        <button
                          onClick={() => handleBooking(booking.id, "accepted")}
                          className="flex-1 bg-[#2ECC71] text-white py-2 rounded-lg hover:bg-[#27AE60] transition-colors text-sm"
                        >
                          Accept
                        </button>
                        <button
                          onClick={() => handleBooking(booking.id, "declined")}
                          className="flex-1 bg-gray-200 text-gray-700 py-2 rounded-lg hover:bg-gray-300 transition-colors text-sm"
                        >
                          Decline
                        </button>
                      </div>
                    ) : (
                      <div className={`text-center text-sm font-semibold py-2 rounded-lg ${
                        booking.status === "accepted" ? "text-green-700 bg-green-100" : "text-gray-500 bg-gray-100"
                      }`}>
                        {booking.status === "accepted" ? "✓ Booking Confirmed" : "✗ Declined"}
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* Right Column */}
          <div className="space-y-6">
            {/* Availability Toggle */}
            <div className="bg-white rounded-xl shadow-md p-6">
              <h3 className="text-lg font-semibold text-gray-800 mb-4">Availability Status</h3>
              <div className="flex items-center justify-between mb-4">
                <span className="text-gray-700">Currently {isAvailable ? "Available" : "Unavailable"}</span>
                <button onClick={() => setIsAvailable(!isAvailable)}>
                  {isAvailable ? (
                    <ToggleRight className="w-12 h-12 text-[#2ECC71]" />
                  ) : (
                    <ToggleLeft className="w-12 h-12 text-gray-400" />
                  )}
                </button>
              </div>
              <div className={`text-xs px-3 py-2 rounded-lg ${isAvailable ? "bg-green-50 text-green-700" : "bg-gray-100 text-gray-500"}`}>
                {isAvailable
                  ? "You are visible to tourists and accepting bookings."
                  : "You are hidden from search results. Toggle to accept bookings."}
              </div>
            </div>

            {/* Verification Badge */}
            <div className="bg-gradient-to-br from-[#2ECC71] to-[#0B5345] text-white rounded-xl shadow-md p-6">
              <div className="flex items-center gap-3 mb-3">
                <CheckCircle className="w-8 h-8" />
                <h3 className="text-lg font-semibold">SylhetGo Verified</h3>
              </div>
              <p className="text-sm text-white/90">
                Your profile has been verified by SylhetGo administrators. This badge increases trust with tourists.
              </p>
            </div>

            {/* Quick Stats */}
            <div className="bg-white rounded-xl shadow-md p-6">
              <h3 className="text-lg font-semibold text-gray-800 mb-4">This Month</h3>
              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <span className="text-sm text-gray-600">Tours Completed</span>
                  <span className="font-semibold text-gray-800">12</span>
                </div>
                <div className="flex items-center justify-between">
                  <span className="text-sm text-gray-600">Revenue Earned</span>
                  <span className="font-semibold text-[#0B5345]">৳48,500</span>
                </div>
                <div className="flex items-center justify-between">
                  <span className="text-sm text-gray-600">New Reviews</span>
                  <span className="font-semibold text-gray-800">8</span>
                </div>
                <div className="flex items-center justify-between">
                  <span className="text-sm text-gray-600">Avg. Rating</span>
                  <span className="font-semibold text-gray-800 flex items-center gap-1">
                    4.9 <Star className="w-3 h-3 fill-yellow-500 text-yellow-500" />
                  </span>
                </div>
              </div>
            </div>

            {/* Messages */}
            <div className="bg-white rounded-xl shadow-md p-6">
              <div className="flex items-center justify-between mb-4">
                <h3 className="text-lg font-semibold text-gray-800">Messages</h3>
                {unreadCount > 0 && (
                  <span className="bg-red-500 text-white text-xs px-2 py-1 rounded-full">{unreadCount} New</span>
                )}
              </div>
              <div className="space-y-3">
                {messages.map((msg, idx) => (
                  <button
                    key={idx}
                    onClick={() => {
                      setActiveMessage(idx);
                      setMessages(prev => prev.map((m, i) => i === idx ? { ...m, unread: false } : m));
                    }}
                    className="w-full p-3 bg-[#F8F9F9] rounded-lg hover:bg-gray-100 cursor-pointer transition-colors text-left"
                  >
                    <div className="flex items-center justify-between mb-1">
                      <span className={`text-sm font-semibold text-gray-800 ${msg.unread ? "text-[#0B5345]" : ""}`}>{msg.from}</span>
                      <span className="text-xs text-gray-500">{msg.time}</span>
                    </div>
                    <p className="text-xs text-gray-600 truncate">{msg.preview}</p>
                    {msg.unread && <div className="w-2 h-2 bg-[#2ECC71] rounded-full mt-1 ml-auto"></div>}
                  </button>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

import { ArrowLeft, Upload, Camera, AlertTriangle, MapPin, Send, Image as ImageIcon, Award, TrendingUp, CheckCircle, X } from "lucide-react";
import { Link, useNavigate } from "react-router";
import { useState, useRef } from "react";

type Submission = { type: string; location: string; status: string; color: string };

export function ContributorPanel() {
  const navigate = useNavigate();

  const [photoForm, setPhotoForm] = useState({ location: "", caption: "", tags: "" });
  const [photoFiles, setPhotoFiles] = useState<string[]>([]);
  const [photoSuccess, setPhotoSuccess] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [updateForm, setUpdateForm] = useState({ type: "", location: "", content: "" });
  const [updateSuccess, setUpdateSuccess] = useState(false);

  const [hazardForm, setHazardForm] = useState({ hazardType: "", location: "", details: "", severity: "" });
  const [hazardSuccess, setHazardSuccess] = useState(false);

  const [submissions, setSubmissions] = useState<Submission[]>([
    { type: "Photo", location: "Sreemangal", status: "Approved", color: "green" },
    { type: "Update", location: "Ratargul", status: "Pending Review", color: "yellow" },
    { type: "Hazard", location: "Jaflong", status: "Published", color: "green" },
  ]);

  const [stats, setStats] = useState({ photos: 47, posts: 23, hazards: 3, views: 12840, votes: 487 });

  const handlePhotoSubmit = () => {
    if (!photoForm.location || !photoForm.caption) return;
    setSubmissions(prev => [{ type: "Photo", location: photoForm.location, status: "Pending Review", color: "yellow" }, ...prev]);
    setStats(prev => ({ ...prev, photos: prev.photos + 1 }));
    setPhotoForm({ location: "", caption: "", tags: "" });
    setPhotoFiles([]);
    setPhotoSuccess(true);
    setTimeout(() => setPhotoSuccess(false), 3000);
  };

  const handleUpdateSubmit = () => {
    if (!updateForm.type || !updateForm.location || !updateForm.content) return;
    setSubmissions(prev => [{ type: "Update", location: updateForm.location, status: "Pending Review", color: "yellow" }, ...prev]);
    setStats(prev => ({ ...prev, posts: prev.posts + 1 }));
    setUpdateForm({ type: "", location: "", content: "" });
    setUpdateSuccess(true);
    setTimeout(() => setUpdateSuccess(false), 3000);
  };

  const handleHazardSubmit = () => {
    if (!hazardForm.hazardType || !hazardForm.location || !hazardForm.details || !hazardForm.severity) return;
    setSubmissions(prev => [{ type: "Hazard", location: hazardForm.location, status: "Under Review", color: "yellow" }, ...prev]);
    setStats(prev => ({ ...prev, hazards: prev.hazards + 1 }));
    setHazardForm({ hazardType: "", location: "", details: "", severity: "" });
    setHazardSuccess(true);
    setTimeout(() => setHazardSuccess(false), 3000);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    setPhotoFiles(files.map(f => f.name));
  };

  const handleLogout = () => navigate("/contributor");

  return (
    <div className="min-h-screen bg-[#F8F9F9]">
      {/* Header */}
      <nav className="bg-[#0B5345] text-white px-8 py-4 shadow-lg">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-4">
            <Link to="/" className="hover:text-[#2ECC71] transition-colors">
              <ArrowLeft className="w-5 h-5" />
            </Link>
            <div>
              <h1 className="text-xl font-semibold">Community Contributor Portal</h1>
              <p className="text-xs text-white/80">Share your travel experiences with the community</p>
            </div>
          </div>
          <button onClick={handleLogout} className="bg-red-500 px-4 py-2 rounded-lg text-sm hover:bg-red-600 transition-colors">
            Logout
          </button>
        </div>
      </nav>

      <div className="max-w-7xl mx-auto px-8 py-12">
        {/* Welcome Section */}
        <div className="bg-gradient-to-r from-[#0B5345] to-[#2ECC71] text-white rounded-xl p-8 mb-8">
          <div className="flex items-center justify-between">
            <div>
              <h2 className="text-3xl font-semibold mb-2">Welcome, TravelExplorer_BD!</h2>
              <p className="text-white/90">Thank you for contributing to the SylhetGo community. Your insights help thousands of travelers.</p>
            </div>
            <div className="text-right">
              <div className="flex items-center justify-end gap-2 mb-2">
                <Award className="w-8 h-8" />
                <span className="text-2xl font-bold">Level 3</span>
              </div>
              <p className="text-sm text-white/80">Trusted Contributor</p>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-3 gap-8">
          {/* Left Column */}
          <div className="col-span-2 space-y-6">
            {/* Upload Travel Photos */}
            <div className="bg-white rounded-xl shadow-md p-6">
              <div className="flex items-center gap-3 mb-6">
                <Camera className="w-6 h-6 text-[#0B5345]" />
                <h3 className="text-xl font-semibold text-gray-800">Upload Travel Photos</h3>
              </div>
              {photoSuccess && (
                <div className="flex items-center gap-2 bg-green-50 border border-green-200 rounded-lg p-3 mb-4 text-green-700 text-sm">
                  <CheckCircle className="w-4 h-4" />
                  Photos submitted for review! Our team will review them within 24 hours.
                </div>
              )}
              <div className="space-y-4">
                <div>
                  <label className="block text-sm text-gray-600 mb-2">Location *</label>
                  <select
                    value={photoForm.location}
                    onChange={e => setPhotoForm(p => ({ ...p, location: e.target.value }))}
                    className="w-full px-4 py-3 bg-[#F8F9F9] rounded-lg outline-none focus:ring-2 focus:ring-[#0B5345]"
                  >
                    <option value="">Select a destination...</option>
                    <option>Sreemangal</option>
                    <option>Ratargul Swamp Forest</option>
                    <option>Jaflong</option>
                    <option>Bholaganj Sada Pathor</option>
                    <option>Shamshernagar</option>
                    <option>Lawachara National Park</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm text-gray-600 mb-2">Photo Upload</label>
                  <input ref={fileInputRef} type="file" multiple accept="image/*" className="hidden" onChange={handleFileChange} />
                  <div
                    className="border-2 border-dashed border-gray-300 rounded-lg p-8 text-center hover:border-[#0B5345] transition-colors cursor-pointer"
                    onClick={() => fileInputRef.current?.click()}
                  >
                    <ImageIcon className="w-12 h-12 text-gray-400 mx-auto mb-3" />
                    {photoFiles.length > 0 ? (
                      <div>
                        <p className="text-[#0B5345] font-medium mb-1">{photoFiles.length} file(s) selected</p>
                        <ul className="text-xs text-gray-500">
                          {photoFiles.slice(0, 3).map((f, i) => <li key={i}>{f}</li>)}
                          {photoFiles.length > 3 && <li>...and {photoFiles.length - 3} more</li>}
                        </ul>
                      </div>
                    ) : (
                      <>
                        <p className="text-gray-600 mb-2">Drag and drop photos here or click to browse</p>
                        <p className="text-xs text-gray-500">Maximum 5 photos, up to 10MB each</p>
                      </>
                    )}
                    <button
                      type="button"
                      className="mt-4 bg-[#0B5345] text-white px-6 py-2 rounded-lg hover:bg-[#0a4538] transition-colors"
                      onClick={e => { e.stopPropagation(); fileInputRef.current?.click(); }}
                    >
                      Choose Files
                    </button>
                  </div>
                </div>
                <div>
                  <label className="block text-sm text-gray-600 mb-2">Caption / Description *</label>
                  <textarea
                    rows={3}
                    value={photoForm.caption}
                    onChange={e => setPhotoForm(p => ({ ...p, caption: e.target.value }))}
                    placeholder="Describe what makes this moment special..."
                    className="w-full px-4 py-3 bg-[#F8F9F9] rounded-lg outline-none focus:ring-2 focus:ring-[#0B5345]"
                  />
                </div>
                <div>
                  <label className="block text-sm text-gray-600 mb-2">Tags (optional)</label>
                  <input
                    type="text"
                    value={photoForm.tags}
                    onChange={e => setPhotoForm(p => ({ ...p, tags: e.target.value }))}
                    placeholder="e.g., tea garden, sunrise, wildlife..."
                    className="w-full px-4 py-3 bg-[#F8F9F9] rounded-lg outline-none focus:ring-2 focus:ring-[#0B5345]"
                  />
                </div>
                <button
                  onClick={handlePhotoSubmit}
                  disabled={!photoForm.location || !photoForm.caption}
                  className="w-full bg-[#2ECC71] text-white py-3 rounded-lg hover:bg-[#27AE60] transition-colors flex items-center justify-center gap-2 disabled:opacity-40 disabled:cursor-not-allowed"
                >
                  <Upload className="w-5 h-5" />
                  Submit Photos for Review
                </button>
              </div>
            </div>

            {/* Post Community Update */}
            <div className="bg-white rounded-xl shadow-md p-6">
              <div className="flex items-center gap-3 mb-6">
                <Send className="w-6 h-6 text-[#0B5345]" />
                <h3 className="text-xl font-semibold text-gray-800">Post Community Update</h3>
              </div>
              {updateSuccess && (
                <div className="flex items-center gap-2 bg-green-50 border border-green-200 rounded-lg p-3 mb-4 text-green-700 text-sm">
                  <CheckCircle className="w-4 h-4" />
                  Update submitted! It will go live after moderation review.
                </div>
              )}
              <div className="space-y-4">
                <div>
                  <label className="block text-sm text-gray-600 mb-2">Update Type *</label>
                  <div className="grid grid-cols-3 gap-3">
                    {["Travel Tip", "Current Conditions", "Review"].map(type => (
                      <button
