    { id: 2, type: "Community Update", user: "LocalGuide_Rafiq", location: "Ratargul Swamp Forest", content: "Water levels are perfect this week for boat tours. Best time to visit is early morning before 9 AM.", timestamp: "4 hours ago", photoCount: 0, status: "pending" },
    { id: 3, type: "Hazard Report", user: "SafetyFirst_User", location: "Jaflong Road", content: "Road construction ongoing near Jaflong entrance. Expect 20-30 minute delays during 10 AM - 4 PM.", timestamp: "6 hours ago", photoCount: 2, status: "pending", priority: "high" },
    { id: 4, type: "Travel Review", user: "Wanderer_Sarah", location: "Bholaganj Sada Pathor", content: "Crystal clear water and stunning white stones. Guide 'Mohan' was excellent - very knowledgeable about local geology!", timestamp: "8 hours ago", photoCount: 5, status: "pending" },
  ]);

  const [flagged, setFlagged] = useState<FlaggedItem[]>([
    { id: 501, type: "Comment", user: "Anonymous_User", reason: "Inappropriate language", flaggedBy: 3, content: "This place is overrated and the guides are...", timestamp: "1 day ago" },
    { id: 502, type: "Photo", user: "PhotoSpammer_123", reason: "Spam/Advertising", flaggedBy: 7, content: "Multiple photos with commercial watermarks", timestamp: "2 days ago" },
  ]);

  const [toast, setToast] = useState("");
  const [viewingItem, setViewingItem] = useState<ContentItem | null>(null);

  const showToast = (msg: string) => {
    setToast(msg);
    setTimeout(() => setToast(""), 3000);
  };

  const handleAction = (id: number, action: "approved" | "rejected") => {
    setQueue(prev => prev.map(item => item.id === id ? { ...item, status: action } : item));
    showToast(action === "approved" ? "✓ Content approved and published!" : "✗ Content rejected.");
    setViewingItem(null);
  };

  const handleApproveAll = () => {
    setQueue(prev => prev.map(item => item.status === "pending" ? { ...item, status: "approved" } : item));
    showToast("✓ All pending content approved and published!");
  };

  const handleRejectAll = () => {
    setQueue(prev => prev.map(item => item.status === "pending" ? { ...item, status: "rejected" } : item));
    showToast("✗ All pending content rejected.");
  };

  const dismissFlag = (id: number) => {
    setFlagged(prev => prev.map(f => f.id === id ? { ...f, dismissed: true } : f));
    showToast("Flags dismissed.");
  };

  const removeContent = (id: number) => {
    setFlagged(prev => prev.filter(f => f.id !== id));
    showToast("Content removed successfully.");
  };

  const pending = queue.filter(q => q.status === "pending");
  const activeFlagged = flagged.filter(f => !f.dismissed);

  return (
    <div className="p-8 relative">
      {toast && (
        <div className="fixed top-6 right-6 bg-[#0B5345] text-white px-6 py-3 rounded-xl shadow-2xl z-50 flex items-center gap-3">
          <span className="text-sm">{toast}</span>
          <button onClick={() => setToast("")}><X className="w-4 h-4" /></button>
        </div>
      )}

      {viewingItem && (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4" onClick={() => setViewingItem(null)}>
          <div className="bg-white rounded-xl max-w-lg w-full p-8 shadow-2xl" onClick={e => e.stopPropagation()}>
            <div className="flex items-center justify-between mb-4">
              <span className={`px-3 py-1 rounded-full text-xs ${
                viewingItem.type === "Photo Upload" ? "bg-blue-100 text-blue-700" :
                viewingItem.type === "Community Update" ? "bg-green-100 text-green-700" :
                viewingItem.type === "Hazard Report" ? "bg-red-100 text-red-700" :
                "bg-purple-100 text-purple-700"
              }`}>{viewingItem.type}</span>
              <button onClick={() => setViewingItem(null)}><X className="w-5 h-5 text-gray-400" /></button>
            </div>
            <p className="font-semibold text-gray-800 mb-1">{viewingItem.user}</p>
            <p className="text-sm text-gray-500 mb-3">{viewingItem.location} • {viewingItem.timestamp}</p>
            {viewingItem.photoCount > 0 && (
              <div className="flex items-center gap-1 text-xs text-gray-600 mb-3">
                <ImageIcon className="w-3 h-3" />{viewingItem.photoCount} photos attached
              </div>
            )}
            <p className="text-gray-700 bg-[#F8F9F9] p-4 rounded-lg mb-6">"{viewingItem.content}"</p>
            <div className="flex gap-3">
              <button onClick={() => handleAction(viewingItem.id, "rejected")} className="flex-1 bg-red-500 text-white py-3 rounded-lg hover:bg-red-600 transition-colors flex items-center justify-center gap-2">
                <XCircle className="w-4 h-4" /> Reject
              </button>
              <button onClick={() => handleAction(viewingItem.id, "approved")} className="flex-1 bg-[#2ECC71] text-white py-3 rounded-lg hover:bg-[#27AE60] transition-colors flex items-center justify-center gap-2">
                <CheckCircle className="w-4 h-4" /> Approve & Publish
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="mb-8">
        <h2 className="text-3xl font-semibold text-gray-800 mb-2">Community Moderation Queue</h2>
        <p className="text-gray-600">Review and approve user-generated content before it goes live</p>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-4 gap-6 mb-8">
        <div className="bg-white rounded-xl shadow-md p-6">
          <MessageSquare className="w-8 h-8 text-[#0B5345] mb-2" />
          <h3 className="text-2xl font-bold text-gray-800 mb-1">{pending.length}</h3>
          <p className="text-sm text-gray-600">Pending Reviews</p>
        </div>
        <div className="bg-white rounded-xl shadow-md p-6 border-l-4 border-red-500">
          <Flag className="w-8 h-8 text-red-500 mb-2" />
          <h3 className="text-2xl font-bold text-gray-800 mb-1">{activeFlagged.length}</h3>
          <p className="text-sm text-gray-600">Flagged Content</p>
        </div>
        <div className="bg-white rounded-xl shadow-md p-6">
          <CheckCircle className="w-8 h-8 text-green-600 mb-2" />
          <h3 className="text-2xl font-bold text-gray-800 mb-1">{queue.filter(q => q.status === "approved").length + 1847}</h3>
          <p className="text-sm text-gray-600">Approved (30 days)</p>
        </div>
        <div className="bg-white rounded-xl shadow-md p-6">
          <XCircle className="w-8 h-8 text-gray-500 mb-2" />
          <h3 className="text-2xl font-bold text-gray-800 mb-1">{queue.filter(q => q.status === "rejected").length + 42}</h3>
          <p className="text-sm text-gray-600">Rejected (30 days)</p>
        </div>
      </div>

      {/* Flagged Content */}
      {activeFlagged.length > 0 && (
        <div className="bg-white rounded-xl shadow-md mb-8 border-l-4 border-red-500">
          <div className="p-6 bg-red-500 text-white">
            <div className="flex items-center gap-3">
              <Flag className="w-6 h-6" />
              <h3 className="text-xl font-semibold">Flagged Content - Requires Immediate Attention</h3>
            </div>
          </div>
          <div className="p-6 space-y-4">
            {activeFlagged.map(item => (
              <div key={item.id} className="border border-red-200 rounded-lg p-5 bg-red-50">
                <div className="flex items-start justify-between mb-3">
                  <div>
                    <div className="flex items-center gap-3 mb-2">
                      <span className="px-3 py-1 bg-red-600 text-white rounded-full text-xs">{item.type}</span>
                      <span className="text-sm text-gray-600">by {item.user}</span>
                    </div>
                    <p className="text-sm text-gray-800 mb-2"><span className="font-semibold">Reason:</span> {item.reason}</p>
                    <p className="text-sm text-gray-600 italic">"{item.content}"</p>
                  </div>
                  <div className="text-right">
                    <p className="text-xs text-gray-500 mb-1">{item.timestamp}</p>
                    <p className="text-xs text-red-600 font-semibold">Flagged by {item.flaggedBy} users</p>
                  </div>
                </div>
                <div className="flex gap-2 mt-4">
                  <button onClick={() => dismissFlag(item.id)} className="flex-1 bg-gray-200 text-gray-700 py-2 rounded-lg hover:bg-gray-300 transition-colors text-sm">
                    Dismiss Flags
                  </button>
                  <button className="flex-1 bg-yellow-500 text-white py-2 rounded-lg hover:bg-yellow-600 transition-colors text-sm">
                    Request Edit
                  </button>
                  <button onClick={() => removeContent(item.id)} className="flex-1 bg-red-600 text-white py-2 rounded-lg hover:bg-red-700 transition-colors text-sm">
                    Remove Content
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Approval Queue */}
      <div className="bg-white rounded-xl shadow-md">
        <div className="p-6 bg-[#0B5345] text-white">
          <h3 className="text-xl font-semibold">Content Approval Queue</h3>
        </div>
        <div className="p-6 space-y-4">
          {queue.map(item => (
            <div
              key={item.id}
              className={`border rounded-lg p-5 transition-colors ${
                item.status === "approved" ? "border-green-300 bg-green-50 opacity-70" :
                item.status === "rejected" ? "border-gray-200 bg-gray-50 opacity-50" :
                item.priority === "high" ? "border-yellow-400 bg-yellow-50 hover:border-[#0B5345]" :
                "border-gray-200 hover:border-[#0B5345]"
              }`}
            >
              <div className="flex items-start justify-between mb-4">
                <div className="flex-1">
                  <div className="flex items-center gap-3 mb-2">
                    <span className={`px-3 py-1 rounded-full text-xs ${
                      item.type === "Photo Upload" ? "bg-blue-100 text-blue-700" :
                      item.type === "Community Update" ? "bg-green-100 text-green-700" :
                      item.type === "Hazard Report" ? "bg-red-100 text-red-700" :
                      "bg-purple-100 text-purple-700"
                    }`}>{item.type}</span>
                    {item.priority === "high" && item.status === "pending" && (
                      <span className="flex items-center gap-1 px-3 py-1 bg-yellow-500 text-white rounded-full text-xs">
                        <AlertTriangle className="w-3 h-3" /> High Priority
                      </span>
                    )}
                    {item.status !== "pending" && (
                      <span className={`px-3 py-1 rounded-full text-xs font-semibold ${
                        item.status === "approved" ? "bg-green-100 text-green-700" : "bg-gray-100 text-gray-600"
                      }`}>
                        {item.status === "approved" ? "✓ Approved" : "✗ Rejected"}
                      </span>
                    )}
                  </div>
                  <div className="flex items-center gap-2 mb-1">
                    <span className="font-semibold text-gray-800">{item.user}</span>
                    <span className="text-gray-400">•</span>
                    <span className="text-sm text-gray-600">{item.location}</span>
                    <span className="text-gray-400">•</span>
                    <span className="text-xs text-gray-500">{item.timestamp}</span>
                  </div>
                  {item.photoCount > 0 && (
                    <div className="flex items-center gap-1 text-xs text-gray-600 mb-2">
                      <ImageIcon className="w-3 h-3" />{item.photoCount} photos attached
                    </div>
                  )}
                  <p className="text-gray-700 bg-white p-3 rounded-lg border border-gray-200">"{item.content}"</p>
                </div>
              </div>
              {item.status === "pending" && (
                <div className="flex gap-2">
                  <button onClick={() => setViewingItem(item)} className="flex-1 bg-gray-200 text-gray-700 py-2 rounded-lg hover:bg-gray-300 transition-colors flex items-center justify-center gap-2 text-sm">
                    <Eye className="w-4 h-4" />{item.photoCount > 0 ? "View Photos" : "View Full Details"}
                  </button>
                  <button className="flex-1 bg-yellow-500 text-white py-2 rounded-lg hover:bg-yellow-600 transition-colors flex items-center justify-center gap-2 text-sm">
                    <Edit2 className="w-4 h-4" />Request Edits
                  </button>
                  <button onClick={() => handleAction(item.id, "rejected")} className="flex-1 bg-red-500 text-white py-2 rounded-lg hover:bg-red-600 transition-colors flex items-center justify-center gap-2 text-sm">
                    <XCircle className="w-4 h-4" />Reject
                  </button>
                  <button onClick={() => handleAction(item.id, "approved")} className="flex-1 bg-[#2ECC71] text-white py-2 rounded-lg hover:bg-[#27AE60] transition-colors flex items-center justify-center gap-2 text-sm">
                    <CheckCircle className="w-4 h-4" />Approve & Publish
                  </button>
                </div>
              )}
            </div>
          ))}
        </div>
        <div className="p-4 bg-[#F8F9F9] border-t border-gray-200">
          <div className="flex items-center justify-between">
            <p className="text-sm text-gray-600">{pending.length} items awaiting review</p>
            {pending.length > 0 && (
              <div className="flex gap-3">
                <button onClick={handleRejectAll} className="bg-red-500 text-white px-4 py-2 rounded-lg hover:bg-red-600 transition-colors text-sm">
                  Reject All
                </button>
                <button onClick={handleApproveAll} className="bg-[#2ECC71] text-white px-4 py-2 rounded-lg hover:bg-[#27AE60] transition-colors text-sm">
                  Approve All
                </button>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

import { DollarSign, Edit2, Save, Plus, Trash2, MapPin, X, CheckCircle } from "lucide-react";
import { useState } from "react";

type Route = {
  id: number;
  from: string;
  to: string;
  distance: string;
  cngFare: string;
  boatFare: string;
  duration: string;
  active: boolean;
};

const defaultRoutes: Route[] = [
  { id: 1, from: "Sylhet", to: "Ratargul", distance: "26 km", cngFare: "350-400", boatFare: "500/boat", duration: "45 min", active: true },
  { id: 2, from: "Sylhet", to: "Jaflong", distance: "62 km", cngFare: "800-900", boatFare: "N/A", duration: "1.5 hr", active: true },
  { id: 3, from: "Sylhet", to: "Sreemangal", distance: "85 km", cngFare: "1100-1200", boatFare: "N/A", duration: "2 hr", active: true },
  { id: 4, from: "Sylhet", to: "Bholaganj", distance: "38 km", cngFare: "500-600", boatFare: "N/A", duration: "1 hr", active: true },
  { id: 5, from: "Sylhet", to: "Shamshernagar", distance: "92 km", cngFare: "1200-1300", boatFare: "N/A", duration: "2.2 hr", active: true },
];

export function FareManager() {
  const [routes, setRoutes] = useState<Route[]>(defaultRoutes);
  const [editingId, setEditingId] = useState<number | null>(null);
  const [editValues, setEditValues] = useState<Partial<Route>>({});
  const [toast, setToast] = useState("");
  const [showAddForm, setShowAddForm] = useState(false);
  const [newRoute, setNewRoute] = useState({ from: "Sylhet", to: "", distance: "", cngFare: "", boatFare: "N/A", duration: "" });
  const [saved, setSaved] = useState(false);

  const showToast = (msg: string) => {
    setToast(msg);
    setTimeout(() => setToast(""), 3000);
  };

  const startEdit = (route: Route) => {
    setEditingId(route.id);
    setEditValues({ ...route });
  };

  const saveEdit = (id: number) => {
    setRoutes(prev => prev.map(r => r.id === id ? { ...r, ...editValues } as Route : r));
    setEditingId(null);
    setEditValues({});
    showToast("✓ Route updated successfully.");
  };

  const cancelEdit = () => {
    setEditingId(null);
    setEditValues({});
  };

  const deleteRoute = (id: number) => {
    const route = routes.find(r => r.id === id);
    setRoutes(prev => prev.filter(r => r.id !== id));
    if (route) showToast(`✗ Route "${route.from} → ${route.to}" deleted.`);
  };

  const toggleActive = (id: number) => {
    setRoutes(prev => prev.map(r => r.id === id ? { ...r, active: !r.active } : r));
  };

  const addRoute = () => {
    if (!newRoute.to || !newRoute.distance || !newRoute.cngFare || !newRoute.duration) return;
    const id = Math.max(...routes.map(r => r.id)) + 1;
    setRoutes(prev => [...prev, { ...newRoute, id, active: true } as Route]);
    setNewRoute({ from: "Sylhet", to: "", distance: "", cngFare: "", boatFare: "N/A", duration: "" });
    setShowAddForm(false);
    showToast(`✓ New route "${newRoute.from} → ${newRoute.to}" added.`);
  };

  const saveAll = () => {
    setSaved(true);
    showToast("✓ All fare changes saved successfully.");
    setTimeout(() => setSaved(false), 3000);
  };

  return (
    <div className="p-8 relative">
      {toast && (
        <div className="fixed top-6 right-6 bg-[#0B5345] text-white px-6 py-3 rounded-xl shadow-2xl z-50 flex items-center gap-3">
          <span className="text-sm">{toast}</span>
          <button onClick={() => setToast("")}><X className="w-4 h-4" /></button>
        </div>
      )}

      <div className="mb-8">
        <h2 className="text-3xl font-semibold text-gray-800 mb-2">Fare & Route Management</h2>
        <p className="text-gray-600">Manage transport fares and routes to ensure transparent pricing for tourists</p>
      </div>

      {/* Quick Stats */}
      <div className="grid grid-cols-4 gap-6 mb-8">
        <div className="bg-white rounded-xl shadow-md p-6">
          <DollarSign className="w-8 h-8 text-[#0B5345] mb-2" />
          <h3 className="text-2xl font-bold text-gray-800 mb-1">{routes.filter(r => r.active).length}</h3>
          <p className="text-sm text-gray-600">Active Routes</p>
        </div>
        <div className="bg-white rounded-xl shadow-md p-6">
          <MapPin className="w-8 h-8 text-blue-600 mb-2" />
          <h3 className="text-2xl font-bold text-gray-800 mb-1">23</h3>
          <p className="text-sm text-gray-600">CNG Operators</p>
        </div>
        <div className="bg-white rounded-xl shadow-md p-6">
          <span className="text-3xl mb-2 block">🚤</span>
          <h3 className="text-2xl font-bold text-gray-800 mb-1">15</h3>
          <p className="text-sm text-gray-600">Boat Services</p>
        </div>
        <div className="bg-white rounded-xl shadow-md p-6 bg-gradient-to-br from-[#0B5345] to-[#2ECC71] text-white">
          <p className="text-sm mb-2">Last Updated</p>
          <h3 className="text-lg font-bold">Today</h3>
        </div>
      </div>

      {/* Add New Route */}
      <div className="mb-6">
        <button
          onClick={() => setShowAddForm(!showAddForm)}
          className="bg-[#2ECC71] text-white px-6 py-3 rounded-lg hover:bg-[#27AE60] transition-colors flex items-center gap-2"
        >
          <Plus className="w-5 h-5" />
          {showAddForm ? "Cancel" : "Add New Route"}
        </button>
      </div>

      {showAddForm && (
        <div className="bg-white rounded-xl shadow-md p-6 mb-6 border-l-4 border-[#2ECC71]">
          <h3 className="text-lg font-semibold text-gray-800 mb-4">New Route Details</h3>
          <div className="grid grid-cols-3 gap-4 mb-4">
            <div>
              <label className="block text-xs text-gray-500 mb-1">From</label>
              <input
                type="text"
                value={newRoute.from}
                onChange={e => setNewRoute(p => ({ ...p, from: e.target.value }))}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-[#0B5345]"
              />
            </div>
            <div>
              <label className="block text-xs text-gray-500 mb-1">To *</label>
              <input
                type="text"
                value={newRoute.to}
                onChange={e => setNewRoute(p => ({ ...p, to: e.target.value }))}
                placeholder="e.g., Jaflong"
                className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-[#0B5345]"
              />
            </div>
            <div>
              <label className="block text-xs text-gray-500 mb-1">Distance *</label>
              <input
                type="text"
                value={newRoute.distance}
                onChange={e => setNewRoute(p => ({ ...p, distance: e.target.value }))}
                placeholder="e.g., 62 km"
                className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-[#0B5345]"
              />
            </div>
            <div>
              <label className="block text-xs text-gray-500 mb-1">CNG Fare (৳) *</label>
              <input
                type="text"
                value={newRoute.cngFare}
                onChange={e => setNewRoute(p => ({ ...p, cngFare: e.target.value }))}
                placeholder="e.g., 800-900"
                className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-[#0B5345]"
              />
            </div>
            <div>
              <label className="block text-xs text-gray-500 mb-1">Boat Fare (৳)</label>
              <input
                type="text"
                value={newRoute.boatFare}
                onChange={e => setNewRoute(p => ({ ...p, boatFare: e.target.value }))}
                placeholder="N/A or 500/boat"
                className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-[#0B5345]"
              />
            </div>
            <div>
              <label className="block text-xs text-gray-500 mb-1">Duration *</label>
              <input
                type="text"
                value={newRoute.duration}
                onChange={e => setNewRoute(p => ({ ...p, duration: e.target.value }))}
                placeholder="e.g., 1.5 hr"
                className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-[#0B5345]"
              />
            </div>
          </div>
          <button
            onClick={addRoute}
            disabled={!newRoute.to || !newRoute.distance || !newRoute.cngFare || !newRoute.duration}
            className="bg-[#0B5345] text-white px-6 py-2 rounded-lg hover:bg-[#0a4538] transition-colors disabled:opacity-40 disabled:cursor-not-allowed flex items-center gap-2"
          >
            <Plus className="w-4 h-4" /> Add Route
          </button>
        </div>
      )}

      {/* Routes Table */}
      <div className="bg-white rounded-xl shadow-md overflow-hidden">
        <div className="p-6 bg-[#0B5345] text-white">
          <h3 className="text-xl font-semibold">Active Transport Routes</h3>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-[#F8F9F9]">
              <tr>
                <th className="px-6 py-4 text-left text-sm font-semibold text-gray-700">Route</th>
                <th className="px-6 py-4 text-left text-sm font-semibold text-gray-700">Distance</th>
                <th className="px-6 py-4 text-left text-sm font-semibold text-gray-700">CNG Fare (৳)</th>
                <th className="px-6 py-4 text-left text-sm font-semibold text-gray-700">Boat Fare (৳)</th>
                <th className="px-6 py-4 text-left text-sm font-semibold text-gray-700">Duration</th>
                <th className="px-6 py-4 text-left text-sm font-semibold text-gray-700">Status</th>
                <th className="px-6 py-4 text-left text-sm font-semibold text-gray-700">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200">
              {routes.map((route) => (
                <tr key={route.id} className={`hover:bg-gray-50 ${!route.active ? "opacity-50" : ""}`}>
                  <td className="px-6 py-4">
                    {editingId === route.id ? (
                      <div className="flex items-center gap-2">
                        <input
                          type="text"
                          value={editValues.from || ""}
                          onChange={e => setEditValues(v => ({ ...v, from: e.target.value }))}
                          className="w-20 px-2 py-1 border border-gray-300 rounded text-sm"
                        />
                        <span>→</span>
                        <input
                          type="text"
                          value={editValues.to || ""}
                          onChange={e => setEditValues(v => ({ ...v, to: e.target.value }))}
                          className="w-24 px-2 py-1 border border-gray-300 rounded text-sm"
                        />
                      </div>
                    ) : (
                      <span className="font-medium text-gray-800">{route.from} → {route.to}</span>
                    )}
                  </td>
                  <td className="px-6 py-4">
                    {editingId === route.id ? (
                      <input
                        type="text"
                        value={editValues.distance || ""}
                        onChange={e => setEditValues(v => ({ ...v, distance: e.target.value }))}
                        className="w-20 px-2 py-1 border border-gray-300 rounded text-sm"
                      />
                    ) : (
                      <span className="text-gray-600">{route.distance}</span>
                    )}
                  </td>
                  <td className="px-6 py-4">
                    {editingId === route.id ? (
                      <input
                        type="text"
                        value={editValues.cngFare || ""}
                        onChange={e => setEditValues(v => ({ ...v, cngFare: e.target.value }))}
                        className="w-28 px-2 py-1 border border-gray-300 rounded text-sm"
                      />
                    ) : (
                      <span className="font-semibold text-[#0B5345]">৳{route.cngFare}</span>
                    )}
                  </td>
                  <td className="px-6 py-4">
                    {editingId === route.id ? (
                      <input
                        type="text"
                        value={editValues.boatFare || ""}
                        onChange={e => setEditValues(v => ({ ...v, boatFare: e.target.value }))}
                        className="w-28 px-2 py-1 border border-gray-300 rounded text-sm"
                      />
                    ) : (
                      <span className={`font-semibold ${route.boatFare === "N/A" ? "text-gray-400" : "text-[#0B5345]"}`}>
                        {route.boatFare === "N/A" ? "N/A" : `৳${route.boatFare}`}
                      </span>
                    )}
                  </td>
                  <td className="px-6 py-4">
                    {editingId === route.id ? (
                      <input
                        type="text"
                        value={editValues.duration || ""}
                        onChange={e => setEditValues(v => ({ ...v, duration: e.target.value }))}
                        className="w-20 px-2 py-1 border border-gray-300 rounded text-sm"
                      />
                    ) : (
                      <span className="text-gray-600">{route.duration}</span>
                    )}
                  </td>
                  <td className="px-6 py-4">
                    <button
                      onClick={() => toggleActive(route.id)}
                      className={`px-3 py-1 rounded-full text-xs cursor-pointer transition-colors ${
                        route.active ? "bg-green-100 text-green-700 hover:bg-green-200" : "bg-gray-100 text-gray-700 hover:bg-gray-200"
                      }`}
                    >
                      {route.active ? "Active" : "Inactive"}
                    </button>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2">
                      {editingId === route.id ? (
                        <>
                          <button
                            onClick={() => saveEdit(route.id)}
                            className="p-2 bg-[#2ECC71] text-white rounded-lg hover:bg-[#27AE60] transition-colors"
                            title="Save"
                          >
                            <Save className="w-4 h-4" />
                          </button>
                          <button
                            onClick={cancelEdit}
                            className="p-2 bg-gray-200 text-gray-600 rounded-lg hover:bg-gray-300 transition-colors"
                            title="Cancel"
                          >
                            <X className="w-4 h-4" />
                          </button>
                        </>
                      ) : (
                        <button
                          onClick={() => startEdit(route)}
                          className="p-2 bg-blue-100 text-blue-600 rounded-lg hover:bg-blue-200 transition-colors"
                          title="Edit"
                        >
                          <Edit2 className="w-4 h-4" />
                        </button>
                      )}
                      <button
                        onClick={() => deleteRoute(route.id)}
                        className="p-2 bg-red-100 text-red-600 rounded-lg hover:bg-red-200 transition-colors"
                        title="Delete"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        <div className="p-6 bg-[#F8F9F9] border-t border-gray-200">
          <div className="flex items-center justify-between">
            <p className="text-sm text-gray-600">
              Showing {routes.length} routes ({routes.filter(r => r.active).length} active)
            </p>
            <button
              onClick={saveAll}
              className="bg-[#0B5345] text-white px-6 py-2 rounded-lg hover:bg-[#0a4538] transition-colors flex items-center gap-2"
            >
              {saved ? <><CheckCircle className="w-4 h-4" /> Saved!</> : "Save All Changes"}
            </button>
          </div>
        </div>
      </div>

      {/* Pricing Guidelines */}
      <div className="mt-8 bg-blue-50 border border-blue-200 rounded-xl p-6">
        <h3 className="text-lg font-semibold text-blue-900 mb-3">Fare Update Guidelines</h3>
        <ul className="text-sm text-blue-800 space-y-2">
          <li>• Fares should be updated quarterly or when significant market changes occur</li>
          <li>• CNG fares typically range ৳12-15 per kilometer</li>
          <li>• Boat fares are per boat (capacity 4-6 passengers) for Ratargul and similar destinations</li>
          <li>• Always verify fares with at least 3 operators before updating</li>
          <li>• Document the source and date of fare verification in the system notes</li>
        </ul>
      </div>
    </div>
  );
}

import { MapPin, Upload, Image as ImageIcon, Plus, Eye, Edit2, Trash2, CheckCircle, X } from "lucide-react";
import { useState, useRef } from "react";

type Spot = {
  id: number;
  name: string;
  location: string;
  status: "Published" | "Draft";
  photos: number;
  views: number;
};

export function SpotPublisher() {
  const [spots, setSpots] = useState<Spot[]>([
    { id: 1, name: "Ratargul Swamp Forest", location: "Gowainghat, Sylhet", status: "Published", photos: 12, views: 8420 },
    { id: 2, name: "Jaflong", location: "Gowainghat, Sylhet", status: "Published", photos: 18, views: 15230 },
    { id: 3, name: "Sreemangal Tea Estates", location: "Sreemangal, Moulvibazar", status: "Published", photos: 24, views: 12840 },
    { id: 4, name: "Bholaganj Sada Pathor", location: "Companiganj, Sylhet", status: "Published", photos: 9, views: 6720 },
    { id: 5, name: "Shamshernagar Heritage Site", location: "Shamshernagar, Moulvibazar", status: "Draft", photos: 5, views: 0 },
  ]);

  const [form, setForm] = useState({
    name: "", location: "", lat: "", lng: "", category: "", bestTime: "", description: "",
  });
  const [formFiles, setFormFiles] = useState<string[]>([]);
  const [toast, setToast] = useState("");
  const [formSuccess, setFormSuccess] = useState("");
  const fileInputRef = useRef<HTMLInputElement>(null);

  const showToast = (msg: string) => {
    setToast(msg);
    setTimeout(() => setToast(""), 3000);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormFiles(Array.from(e.target.files || []).map(f => f.name));
  };

  const handlePublish = (asDraft = false) => {
    if (!form.name || !form.location || !form.description) return;
    const newSpot: Spot = {
      id: Math.max(...spots.map(s => s.id)) + 1,
      name: form.name,
      location: form.location,
      status: asDraft ? "Draft" : "Published",
      photos: formFiles.length || 0,
      views: 0,
    };
    setSpots(prev => [newSpot, ...prev]);
    setForm({ name: "", location: "", lat: "", lng: "", category: "", bestTime: "", description: "" });
    setFormFiles([]);
    setFormSuccess(asDraft ? "Spot saved as draft." : "Spot published successfully!");
    showToast(asDraft ? "📝 Saved as draft." : `✓ "${newSpot.name}" is now live!`);
    setTimeout(() => setFormSuccess(""), 4000);
  };

  const handleDelete = (id: number) => {
    const spot = spots.find(s => s.id === id);
    setSpots(prev => prev.filter(s => s.id !== id));
    if (spot) showToast(`✗ "${spot.name}" deleted.`);
  };

  const handleToggleStatus = (id: number) => {
    setSpots(prev => prev.map(s =>
      s.id === id
        ? { ...s, status: s.status === "Published" ? "Draft" : "Published" }
        : s
    ));
  };

  const totalViews = spots.reduce((sum, s) => sum + s.views, 0);
  const totalPhotos = spots.reduce((sum, s) => sum + s.photos, 0);

  return (
    <div className="p-8 relative">
      {toast && (
        <div className="fixed top-6 right-6 bg-[#0B5345] text-white px-6 py-3 rounded-xl shadow-2xl z-50 flex items-center gap-3">
          <span className="text-sm">{toast}</span>
          <button onClick={() => setToast("")}><X className="w-4 h-4" /></button>
        </div>
      )}

      <div className="mb-8">
        <h2 className="text-3xl font-semibold text-gray-800 mb-2">Spot & Content Publisher</h2>
        <p className="text-gray-600">Add and manage destination listings with high-quality imagery</p>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-4 gap-6 mb-8">
        <div className="bg-white rounded-xl shadow-md p-6">
          <MapPin className="w-8 h-8 text-[#0B5345] mb-2" />
          <h3 className="text-2xl font-bold text-gray-800 mb-1">{spots.filter(s => s.status === "Published").length}</h3>
          <p className="text-sm text-gray-600">Published Spots</p>
        </div>
        <div className="bg-white rounded-xl shadow-md p-6">
          <ImageIcon className="w-8 h-8 text-blue-600 mb-2" />
          <h3 className="text-2xl font-bold text-gray-800 mb-1">{totalPhotos}</h3>
          <p className="text-sm text-gray-600">Total Photos</p>
        </div>
        <div className="bg-white rounded-xl shadow-md p-6">
          <Eye className="w-8 h-8 text-purple-600 mb-2" />
          <h3 className="text-2xl font-bold text-gray-800 mb-1">{totalViews >= 1000 ? `${(totalViews / 1000).toFixed(0)}K` : totalViews}</h3>
          <p className="text-sm text-gray-600">Total Views</p>
        </div>
        <div className="bg-white rounded-xl shadow-md p-6">
          <span className="text-3xl mb-2 block">📝</span>
          <h3 className="text-2xl font-bold text-gray-800 mb-1">{spots.filter(s => s.status === "Draft").length}</h3>
          <p className="text-sm text-gray-600">Draft Spots</p>
        </div>
      </div>

      {/* Add New Spot Form */}
      <div className="bg-white rounded-xl shadow-md p-6 mb-8">
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-3">
            <Plus className="w-6 h-6 text-[#0B5345]" />
            <h3 className="text-xl font-semibold text-gray-800">Add New Destination</h3>
          </div>
          {formSuccess && (
            <div className="flex items-center gap-2 text-green-700 text-sm">
              <CheckCircle className="w-4 h-4" />
              {formSuccess}
            </div>
          )}
        </div>

        <div className="grid grid-cols-2 gap-6">
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Spot Name *</label>
              <input
                type="text"
                value={form.name}
                onChange={e => setForm(p => ({ ...p, name: e.target.value }))}
                placeholder="e.g., Sreemangal Tea Estates"
                className="w-full px-4 py-3 bg-[#F8F9F9] rounded-lg outline-none focus:ring-2 focus:ring-[#0B5345]"
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Location *</label>
              <input
                type="text"
                value={form.location}
                onChange={e => setForm(p => ({ ...p, location: e.target.value }))}
                placeholder="e.g., Sreemangal, Moulvibazar"
                className="w-full px-4 py-3 bg-[#F8F9F9] rounded-lg outline-none focus:ring-2 focus:ring-[#0B5345]"
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">GPS Coordinates</label>
              <div className="grid grid-cols-2 gap-3">
                <input
                  type="text"
                  value={form.lat}
                  onChange={e => setForm(p => ({ ...p, lat: e.target.value }))}
                  placeholder="Latitude"
                  className="px-4 py-3 bg-[#F8F9F9] rounded-lg outline-none focus:ring-2 focus:ring-[#0B5345]"
                />
                <input
                  type="text"
                  value={form.lng}
                  onChange={e => setForm(p => ({ ...p, lng: e.target.value }))}
                  placeholder="Longitude"
                  className="px-4 py-3 bg-[#F8F9F9] rounded-lg outline-none focus:ring-2 focus:ring-[#0B5345]"
                />
              </div>
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Category *</label>
              <select
                value={form.category}
                onChange={e => setForm(p => ({ ...p, category: e.target.value }))}
                className="w-full px-4 py-3 bg-[#F8F9F9] rounded-lg outline-none focus:ring-2 focus:ring-[#0B5345]"
              >
                <option value="">Select category...</option>
                <option>Nature & Wildlife</option>
                <option>Spiritual & Heritage</option>
                <option>Adventure & Trekking</option>
                <option>Cultural Experience</option>
                <option>Tea Tourism</option>
              </select>
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Best Time to Visit</label>
              <input
                type="text"
                value={form.bestTime}
                onChange={e => setForm(p => ({ ...p, bestTime: e.target.value }))}
                placeholder="e.g., October to April"
                className="w-full px-4 py-3 bg-[#F8F9F9] rounded-lg outline-none focus:ring-2 focus:ring-[#0B5345]"
              />
            </div>
          </div>

          <div className="space-y-4">
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Description *</label>
              <textarea
                rows={6}
                value={form.description}
                onChange={e => setForm(p => ({ ...p, description: e.target.value }))}
                placeholder="Provide a detailed, engaging description of the destination..."
                className="w-full px-4 py-3 bg-[#F8F9F9] rounded-lg outline-none focus:ring-2 focus:ring-[#0B5345]"
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Upload Photographs</label>
              <input ref={fileInputRef} type="file" multiple accept="image/*" className="hidden" onChange={handleFileChange} />
              <div
                className="border-2 border-dashed border-gray-300 rounded-lg p-6 text-center hover:border-[#0B5345] transition-colors cursor-pointer"
                onClick={() => fileInputRef.current?.click()}
              >
                <ImageIcon className="w-12 h-12 text-gray-400 mx-auto mb-3" />
                {formFiles.length > 0 ? (
                  <div>
                    <p className="text-[#0B5345] font-medium">{formFiles.length} file(s) selected</p>
                    <p className="text-xs text-gray-500 mt-1">{formFiles.slice(0, 2).join(", ")}{formFiles.length > 2 ? ` +${formFiles.length - 2} more` : ""}</p>
                  </div>
                ) : (
                  <>
                    <p className="text-gray-600 mb-2">Drag realistic local photography here</p>
                    <p className="text-xs text-gray-500 mb-3">Minimum 3 photos, maximum 20. Each up to 15MB.</p>
                  </>
                )}
                <button
                  type="button"
                  className="mt-2 bg-[#0B5345] text-white px-6 py-2 rounded-lg hover:bg-[#0a4538] transition-colors flex items-center gap-2 mx-auto"
                  onClick={e => { e.stopPropagation(); fileInputRef.current?.click(); }}
                >
                  <Upload className="w-4 h-4" />
                  Choose Files
                </button>
              </div>
            </div>
            <div className="flex gap-3">
              <button
                onClick={() => handlePublish(true)}
                disabled={!form.name || !form.location || !form.description}
                className="flex-1 bg-gray-200 text-gray-700 py-3 rounded-lg hover:bg-gray-300 transition-colors disabled:opacity-40 disabled:cursor-not-allowed"
              >
                Save as Draft
              </button>
              <button
                onClick={() => handlePublish(false)}
                disabled={!form.name || !form.location || !form.description}
                className="flex-1 bg-[#2ECC71] text-white py-3 rounded-lg hover:bg-[#27AE60] transition-colors disabled:opacity-40 disabled:cursor-not-allowed"
              >
                Publish Spot
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Existing Spots Management */}
      <div className="bg-white rounded-xl shadow-md overflow-hidden">
        <div className="p-6 bg-[#0B5345] text-white">
          <h3 className="text-xl font-semibold">Manage Existing Spots ({spots.length})</h3>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-[#F8F9F9]">
              <tr>
                <th className="px-6 py-4 text-left text-sm font-semibold text-gray-700">Spot Name</th>
                <th className="px-6 py-4 text-left text-sm font-semibold text-gray-700">Location</th>
                <th className="px-6 py-4 text-left text-sm font-semibold text-gray-700">Photos</th>
                <th className="px-6 py-4 text-left text-sm font-semibold text-gray-700">Total Views</th>
                <th className="px-6 py-4 text-left text-sm font-semibold text-gray-700">Status</th>
                <th className="px-6 py-4 text-left text-sm font-semibold text-gray-700">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200">
              {spots.map((spot) => (
                <tr key={spot.id} className="hover:bg-gray-50">
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <MapPin className="w-5 h-5 text-[#0B5345]" />
                      <span className="font-medium text-gray-800">{spot.name}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-sm text-gray-600">{spot.location}</td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2">
                      <ImageIcon className="w-4 h-4 text-gray-500" />
                      <span className="text-sm text-gray-700">{spot.photos} photos</span>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2">
                      <Eye className="w-4 h-4 text-gray-500" />
                      <span className="text-sm text-gray-700">{spot.views.toLocaleString()}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <button
                      onClick={() => handleToggleStatus(spot.id)}
                      className={`px-3 py-1 rounded-full text-xs cursor-pointer transition-colors ${
                        spot.status === "Published"
                          ? "bg-green-100 text-green-700 hover:bg-green-200"
                          : "bg-yellow-100 text-yellow-700 hover:bg-yellow-200"
                      }`}
                    >
                      {spot.status}
                    </button>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2">
                      <button className="p-2 bg-blue-100 text-blue-600 rounded-lg hover:bg-blue-200 transition-colors" title="Edit">
                        <Edit2 className="w-4 h-4" />
                      </button>
                      <button className="p-2 bg-purple-100 text-purple-600 rounded-lg hover:bg-purple-200 transition-colors" title="Preview">
                        <Eye className="w-4 h-4" />
                      </button>
                      <button
                        onClick={() => handleDelete(spot.id)}
                        className="p-2 bg-red-100 text-red-600 rounded-lg hover:bg-red-200 transition-colors"
                        title="Delete"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Content Guidelines */}
      <div className="mt-8 bg-green-50 border border-green-200 rounded-xl p-6">
        <h3 className="text-lg font-semibold text-green-900 mb-3">Content Quality Guidelines</h3>
        <ul className="text-sm text-green-800 space-y-2">
          <li>• Use realistic, high-resolution photography from actual locations</li>
          <li>• Avoid generic stock images — prioritize authentic local photography</li>
          <li>• Provide accurate GPS coordinates for navigation purposes</li>
          <li>• Include seasonal accessibility information (especially for Haor areas)</li>
          <li>• Highlight unique local features and indigenous cultural aspects</li>
        </ul>
      </div>
    </div>
  );
}

