import { useState, useEffect } from "react";
import { Bus, Train, Fuel, MapPin, Clock, DollarSign, Search, RefreshCw } from "lucide-react";
import { useLang } from "../../context/LanguageContext";

type Route = {
  id: number;
  route_type: string;
  from_location: string;
  to_location: string;
  distance_km: number;
  fare_min: number;
  fare_max: number;
  duration: string;
  notes: string;
  schedule: string | null;
};

const TABS = ["cng", "bus", "train"] as const;

export function TransportHub() {
  const { tx } = useLang();
  const [tab, setTab] = useState<typeof TABS[number]>("cng");
  const [routes, setRoutes] = useState<Route[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");

  useEffect(() => {
    setLoading(true);
    fetch(`/api/transport?type=${tab}`)
      .then(r => r.json())
